IF DB_ID('AffirmationsDb') IS NULL CREATE DATABASE AffirmationsDb; 
GO
USE AffirmationsDb; 
GO
IF OBJECT_ID('Categories','U') IS NULL CREATE TABLE Categories (Id INT IDENTITY(1,1) PRIMARY KEY, Name NVARCHAR(100) NOT NULL UNIQUE, Description NVARCHAR(255), CreatedAt DATETIME2 DEFAULT SYSUTCDATETIME()); 
GO
IF OBJECT_ID('Affirmations','U') IS NULL CREATE TABLE Affirmations (Id INT IDENTITY(1,1) PRIMARY KEY, Text NVARCHAR(500) NOT NULL, CategoryId INT NOT NULL, Author NVARCHAR(100) NULL, Mood NVARCHAR(50) NULL, IsActive BIT DEFAULT 1, CreatedAt DATETIME2 DEFAULT SYSUTCDATETIME(), CONSTRAINT FK_Affirmations_Categories FOREIGN KEY (CategoryId) REFERENCES Categories(Id));
GO
IF OBJECT_ID('Tags','U') IS NULL CREATE TABLE Tags (Id INT IDENTITY(1,1) PRIMARY KEY, Name NVARCHAR(50) NOT NULL UNIQUE); 
GO
IF OBJECT_ID('AffirmationTags','U') IS NULL CREATE TABLE AffirmationTags (AffirmationId INT NOT NULL, TagId INT NOT NULL, CreatedAt DATETIME2 DEFAULT SYSUTCDATETIME(), PRIMARY KEY (AffirmationId, TagId), CONSTRAINT FK_AffirmationTags_Affirmations FOREIGN KEY (AffirmationId) REFERENCES Affirmations(Id) ON DELETE CASCADE, CONSTRAINT FK_AffirmationTags_Tags FOREIGN KEY (TagId) REFERENCES Tags(Id) ON DELETE CASCADE);
GO
IF OBJECT_ID('UserFavorites','U') IS NULL CREATE TABLE UserFavorites (Id INT IDENTITY(1,1) PRIMARY KEY, UserId NVARCHAR(100) NOT NULL, AffirmationId INT NOT NULL, CreatedAt DATETIME2 DEFAULT SYSUTCDATETIME(), CONSTRAINT FK_UserFavorites_Affirmations FOREIGN KEY (AffirmationId) REFERENCES Affirmations(Id) ON DELETE CASCADE); 
GO
